css_snippet:
/* For larger headlines to prevent an airy feel */
h1, .hero-title {
  letter-spacing: -0.02em; /* Slightly tighter */
}

/* For body text to enhance readability */
p, .body-text {
  letter-spacing: 0.01em; /* Slightly looser */
  line-height: 1.6; /* Complement with good line-height */
}

/* For small, uppercase text (e.g., labels, navigation) */
.label, .nav-item {
  text-transform: uppercase;
  letter-spacing: 0.08em; /* Often needs more space */
}
